module mux4to1 (
    input [1:0] data_in_0,
    input [1:0] in1,
    input [1:0] in2,
    input [1:0] in3,
    input [1:0] sel,
    output reg [1:0] out
);always @(*) begin
    case (sel)
        2'b00: out = data_in_0;
        2'b01: out = in1;
        2'b10: out = in2;
        2'b11: out = in3;
        default: out = 2'b00;
    endcase
end

endmodule
